import base64
import hashlib
from datetime import datetime
from pyotp import random_base32key, totp
from qrcode import QRCode, QRImageRenderer
from io import BytesIO

# Create TOTP secret for a user
def create_totp(username):
    secret = random_base32key()
    with open('secrets.txt', 'a') as f:
        f.write("{}:{}\n".format(username, secret))
    
    return secret

# Generate TOTP code for a user
def get_totp(secret):
    return totp.get_totp_step(secret)

# Validate the provided TOTP code
def validate_totp(provided_code, secret):
    expected = get_totp(secret)
    return int(provided_code) == expected

# Create a QR code for a user
def create_qr(username, secret):
    qr = QRCode(QRImageRenderer())
    url = "otpauth://totp/{}?secret={}".format(username, secret)
    img = qr.make_image(data=url)
    
    stream = BytesIO()
    img.save(stream, 'JPEG')
    return base64.b64encode(stream.getvalue()).decode('utf-8')